+import { AuthProvider, OAuthConfig, TokenResponse } from '../types';
+
+export class OAuthProvider implements AuthProvider {
+  private config: OAuthConfig;
+
+  constructor(config: OAuthConfig) {
+    this.config = config;
+  }
+
+  async authorize(redirectUri: string): Promise<string> {
+    const params = new URLSearchParams({
+      client_id: this.config.clientId,
+      redirect_uri: redirectUri,
+      response_type: 'code',
+      scope: this.config.scopes.join(' '),
+      code_challenge_method: 'S256',
+      code_challenge: await this.generateCodeChallenge(),
+    });
+    return `${this.config.authorizationEndpoint}?${params}`;
+  }
+
+  async exchangeCode(code: string, codeVerifier: string): Promise<TokenResponse> {
+    const response = await fetch(this.config.tokenEndpoint, {
+      method: 'POST',
+      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
+      body: new URLSearchParams({
+        grant_type: 'authorization_code',
+        code,
+        code_verifier: codeVerifier,
+        client_id: this.config.clientId,
+      }),
+    });
+    return response.json();
+  }
+
+  private async generateCodeChallenge(): Promise<string> {
+    // PKCE S256 challenge generation
+    const verifier = crypto.randomUUID();
+    const encoder = new TextEncoder();
+    const data = encoder.encode(verifier);
+    const hash = await crypto.subtle.digest('SHA-256', data);
+    return btoa(String.fromCharCode(...new Uint8Array(hash)))
+      .replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
+  }
+}

